import 'package:flutter/material.dart';
import '../../domain/entities/chat_room.dart';
class ChatRoomTile extends StatelessWidget{final ChatRoom room; final String currentUserId; final VoidCallback onTap; const ChatRoomTile({super.key,required this.room,required this.currentUserId,required this.onTap}); @override Widget build(BuildContext context){final unread=room.unreadCountFor(currentUserId); final other=room.otherParticipantId(currentUserId); return ListTile(onTap:onTap,leading:CircleAvatar(child:Text(other.isEmpty?'?':other.characters.first.toUpperCase())),title:Text('Chat with $other',maxLines:1,overflow:TextOverflow.ellipsis),subtitle:Text(room.lastMessageText??'No messages yet',maxLines:1,overflow:TextOverflow.ellipsis),trailing:unread>0?Badge(label:Text(unread.toString())):Text(_timeText(room.lastMessageAt??room.updatedAt),style:Theme.of(context).textTheme.bodySmall));} String _timeText(DateTime d)=>'${d.hour.toString().padLeft(2,'0')}:${d.minute.toString().padLeft(2,'0')}';}
